import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import API_PATHS from 'lib/http/apiPaths';
import { optionLabelByValue, useParcelOptions } from 'features/shared/selectOptionHelpers';

export default function NotesPage() {
  const parcelOptions = useParcelOptions();

  return (
    <CrudResourceModule
      title="Anotaciones Administrativas"
      path={API_PATHS.notes}
      columns={[
        { key: 'parcela', label: 'Parcela', render: (row) => optionLabelByValue(parcelOptions, row.parcela) },
        { key: 'tipo', label: 'Tipo' },
        { key: 'fecha_evento', label: 'Fecha' },
        { key: 'texto', label: 'Texto' }
      ]}
      fields={[
        { name: 'parcela', label: 'Parcela', type: 'select', required: true, options: parcelOptions },
        {
          name: 'tipo',
          label: 'Tipo',
          type: 'select',
          required: true,
          options: [
            { value: 'ADMINISTRATIVA', label: 'Administrativa' },
            { value: 'COBRANZA', label: 'Cobranza' },
            { value: 'OPERATIVA', label: 'Operativa' },
            { value: 'ALERTA', label: 'Alerta' }
          ]
        },
        { name: 'fecha_evento', label: 'Fecha evento', type: 'date' },
        { name: 'texto', label: 'Texto', type: 'textarea', fullWidth: true, required: true }
      ]}
      defaultOrdering="-fecha_evento"
    />
  );
}
